1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
4	
5	const CURSE_SURCHARGE = 0.5;
6	const HIGH_ENCHANT_SURCHARGE = 0.3;
7	const HIGH_ENCHANT_THRESHOLD = 5;
8	const LOYALTY_DISCOUNT = 0.2;
9	const LOYALTY_THRESHOLD = 2;
10	const FIRST_INSURANCE_SURCHARGE = 0.1;
11	const FOLLOW_UP_DISCOUNT = 0.15;
12	const DEDUCTIBLE = 100;
13	const HIGH_ENCHANT_PAYOUT_THRESHOLD = 8;
14	const HIGH_ENCHANT_REIMBURSEMENT_RATE = 0.5;
15	const FULL_REIMBURSEMENT_RATE = 1;
16	
17	type Customer = { yearsWithMHPCO: number };
18	type Damage = { itemType: string; amount: number };
19	type Incident = { cause: string; damages: Damage[] };
20	type QuoteStep = { op: "quote"; items: Item[] };
21	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
22	type Step = QuoteStep | ClaimStep;
23	type Scenario = { customer: Customer; steps: Step[] };
24	type QuoteResult = { premium: number };
25	type ClaimResult = { payout: number; remainingCap: number };
26	type StepResult = QuoteResult | ClaimResult;
27	
28	const BASE_PREMIUMS: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
33	  rune: 25,
34	  moonstone: 25,
35	};
36	
37	const INSURANCE_VALUES: Record<string, number> = {
38	  sword: 1000,
39	  amulet: 600,
40	  staff: 800,
41	  potion: 400,
42	  rune: 250,
43	  moonstone: 250,
44	};
45	
46	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
47	const BLOCK_PREMIUM = 60;
48	const BLOCK_SIZE = 3;
49	
50	const itemSurcharge = (item: Item): number => {
51	  const base = BASE_PREMIUMS[item.type];
52	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE : 0;
53	  const enchantSurcharge =
54	    (item.enchantment ?? 0) >= HIGH_ENCHANT_THRESHOLD ? base * HIGH_ENCHANT_SURCHARGE : 0;
55	  return curseSurcharge + enchantSurcharge;
56	};
57	
58	const componentTypePremium = (type: string, count: number): number =>
59	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
60	
61	const policyBasePremium = (items: Item[]): number => {
62	  const components = items.filter((item) => COMPONENT_TYPES.has(item.type));
63	  const nonComponents = items.filter((item) => !COMPONENT_TYPES.has(item.type));
64	  const nonComponentTotal = nonComponents.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
65	  const componentCounts = countBy(components, (item) => item.type);
66	  const componentTotal = Object.entries(componentCounts).reduce(
67	    (sum, [type, count]) => sum + componentTypePremium(type, count),
68	    0,
69	  );
70	  return nonComponentTotal + componentTotal;
71	};
72	
73	const insuranceSum = (items: Item[]): number =>
74	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
75	
76	const validateItems = (items: Item[]): void => {
77	  for (const item of items) {
78	    if (!(item.type in BASE_PREMIUMS)) {
79	      throw new Error(`Unknown item type: ${item.type}`);
80	    }
81	  }
82	};
83	
84	const quote = (items: Item[], customer: Customer, isFollowUp: boolean): QuoteResult => {
85	  validateItems(items);
86	  const base = policyBasePremium(items);
87	  const surcharges = items.reduce((sum, item) => sum + itemSurcharge(item), 0);
88	  const loyalty = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD ? -base * LOYALTY_DISCOUNT : 0;
89	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE;
90	  const followUp = isFollowUp ? -base * FOLLOW_UP_DISCOUNT : 0;
91	  const premium = Math.ceil(base + surcharges + loyalty + firstInsurance + followUp + PROCESSING_FEE);
92	  return { premium };
93	};
94	
95	type Policy = {
96	  items: Item[];
97	  remainingCap: number;
98	};
99	
100	const reimbursementRate = (item: Item): number =>
101	  (item.enchantment ?? 0) >= HIGH_ENCHANT_PAYOUT_THRESHOLD
102	    ? HIGH_ENCHANT_REIMBURSEMENT_RATE
103	    : FULL_REIMBURSEMENT_RATE;
104	
105	const damagePayout = (damage: Damage, item: Item): number =>
106	  Math.max(0, damage.amount * reimbursementRate(item) - DEDUCTIBLE);
107	
108	const findInsuredItem = (policy: Policy, damage: Damage): Item | undefined =>
109	  policy.items.find((item) => item.type === damage.itemType);
110	
111	const countBy = <T>(items: T[], getType: (item: T) => string): Record<string, number> => {
112	  const counts: Record<string, number> = {};
113	  for (const item of items) {
114	    const type = getType(item);
115	    counts[type] = (counts[type] ?? 0) + 1;
116	  }
117	  return counts;
118	};
119	
120	const validateDamages = (incident: Incident, policy: Policy): void => {
121	  for (const damage of incident.damages) {
122	    if (damage.amount < 0) {
123	      throw new Error(`Damage amount cannot be negative: ${damage.amount}`);
124	    }
125	  }
126	  const insuredCounts = countBy(policy.items, (item) => item.type);
127	  const damageCounts = countBy(incident.damages, (damage) => damage.itemType);
128	  for (const type of Object.keys(damageCounts)) {
129	    if ((insuredCounts[type] ?? 0) < damageCounts[type]) {
130	      throw new Error(`Claim has more ${type} damages than insured`);
131	    }
132	  }
133	};
134	
135	const grossPayout = (incident: Incident, policy: Policy): number =>
136	  incident.damages.reduce((sum, damage) => {
137	    const item = findInsuredItem(policy, damage);
138	    return item ? sum + damagePayout(damage, item) : sum;
139	  }, 0);
140	
141	const claim = (incident: Incident, policy: Policy): ClaimResult => {
142	  validateDamages(incident, policy);
143	  const payout = Math.floor(Math.min(grossPayout(incident, policy), policy.remainingCap));
144	  policy.remainingCap -= payout;
145	  return { payout, remainingCap: policy.remainingCap };
146	};
147	
148	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
149	  let quoteCount = 0;
150	  const policies: Record<number, Policy> = {};
151	  const results: StepResult[] = scenario.steps.map((step, index) => {
152	    if (step.op === "quote") {
153	      const isFollowUp = quoteCount > 0;
154	      quoteCount += 1;
155	      const sum = insuranceSum(step.items);
156	      policies[index] = { items: step.items, remainingCap: sum * 2 };
157	      return quote(step.items, scenario.customer, isFollowUp);
158	    } else {
159	      return claim(step.incident, policies[step.policy]);
160	    }
161	  });
162	  return { results };
163	};
